def test_roundtrip_json_invocationcontextdecision():
    """Test that load -> save -> load produces equivalent data."""
    json_data = r"""
    {
      "candidateId": "memory:project-plan",
      "reason": "included by relevance ranking"
    }
    """
    original_data = json.loads(json_data, strict=False)
    instance = InvocationContextDecision.load(original_data)
    saved_data = instance.save()
    reloaded = InvocationContextDecision.load(saved_data)
    assert reloaded is not None
    assert reloaded.candidate_id == "memory:project-plan"
    assert reloaded.reason == "included by relevance ranking"


